use serde::Serialize;
use serde_json;

#[derive(Serialize)]
struct Greeting { message: String }

pub fn handle_greet(name: Option<&str>) -> (u16, String) {
    let name = name.unwrap_or("World");
    let body = serde_json::to_string(&Greeting { message: format!("Hello, {}!", name) }).unwrap();
    (200, body)
}

