S Url {
    scheme: s,
    host: s,
    port: ?u16,
    path: s,
}

+f parse_url(raw: &s) -> R[Url, s] {
    v parts = raw.split("://");
    ? parts.len() < 2 { ret R.Err("missing scheme"); }
    v scheme = parts[0];
    v rest = parts[1];
    v slash_idx = rest.find('/').unwrap_or(rest.len());
    v authority = rest[0..slash_idx];
    v path = rest[slash_idx..];
    v colon_idx = authority.find(':');
    ? colon_idx {
        ?Some(ci) => {
            v host = authority[0..ci];
            v port = authority[ci+1..].parse_u16();
            R.Ok(@Url { scheme: scheme, host: host, port: ?Some(port), path: path })
        },
        ?None => R.Ok(@Url { scheme: scheme, host: authority, port: ?None, path: path }),
    }
}

rust_equivalent.rs_source:
struct Url { scheme: String, host: String, port: Option<u16>, path: String }

pub fn parse_url(raw: &str) -> Result<Url, String> {
    let parts: Vec<&str> = raw.splitn(2, "://").collect();
    if parts.len() < 2 { return Err("missing scheme".into()); }
    let scheme = parts[0].to_string();
    let rest = parts[1];
    let slash_idx = rest.find('/').unwrap_or(rest.len());
    let authority = &rest[..slash_idx];
    let path = &rest[slash_idx..];
    if let Some(ci) = authority.find(':') {
        let host = authority[..ci].to_string();
        let port = authority[ci+1..].parse::<u16>().map_err(|e| e.to_string())?;
        Ok(Url { scheme, host, port: Some(port), path: path.to_string() })
    } else {
        Ok(Url { scheme, host: authority.to_string(), port: None, path: path.to_string() })
    }
}

