E Method { Get, Post, Put, Delete }

S Route {
    method: Method,
    path: s,
    handler: f(&Request) -> Response,
}

S Router { routes: [Route]~ }

I Router {
    +f new() -> Router { @Router { routes: [] } }
    +f add(&!self, method: Method, path: s, handler: f(&Request) -> Response) {
        self.routes.push(@Route { method: method, path: path, handler: handler });
    }
    +f dispatch(&self, req: &Request) -> Response / io, net {
        @ route : &self.routes {
            ? route.method == req.method && route.path == req.path {
                ret (route.handler)(req);
            }
        }
        Response.new(Status.NotFound, "Not Found")
    }
}

rust_equivalent.rs_source:
enum Method { Get, Post, Put, Delete }

struct Route { method: Method, path: String, handler: fn(&str) -> (u16, String) }

struct Router { routes: Vec<Route> }

impl Router {
    pub fn new() -> Self { Self { routes: Vec::new() } }
    pub fn add(&mut self, method: Method, path: String, handler: fn(&str) -> (u16, String)) {
        self.routes.push(Route { method, path, handler });
    }
    pub fn dispatch(&self, method: &Method, path: &str, body: &str) -> (u16, String) {
        for route in &self.routes {
            if std::mem::discriminant(&route.method) == std::mem::discriminant(method) && route.path == path {
                return (route.handler)(body);
            }
        }
        (404, "Not Found".to_string())
    }
}

