S Config {
    name: s,
    version: s,
    features: [s]~,
}

+f to_json(config: &Config) -> s {
    m parts: [s]~ = [];
    parts.push(f"\"name\":\"{config.name}\"");
    parts.push(f"\"version\":\"{config.version}\"");
    m feat_strs: [s]~ = [];
    @ feat : &config.features {
        feat_strs.push(f"\"{feat}\"");
    }
    parts.push(f"\"features\":[{feat_strs.join(",")}]");
    f"{{{parts.join(",")}}}"
}

rust_equivalent.rs_source:
struct Config { name: String, version: String, features: Vec<String> }

pub fn to_json(config: &Config) -> String {
    let feats: Vec<String> = config.features.iter()
        .map(|f| format!("\"{}\"" , f)).collect();
    format!(
        "{{\"name\":\"{}\",\"version\":\"{}\",\"features\":[{}]}}",
        config.name, config.version, feats.join(",")
    )
}

