struct CorsConfig { allowed_origins: Vec<String>, allowed_methods: Vec<String>, max_age: u32 }

pub fn apply_cors(resp: &mut http::Response<String>, config: &CorsConfig) {
    let origins = config.allowed_origins.join(", ");
    let methods = config.allowed_methods.join(", ");
    resp.headers_mut().insert("Access-Control-Allow-Origin", origins.parse().unwrap());
    resp.headers_mut().insert("Access-Control-Allow-Methods", methods.parse().unwrap());
    resp.headers_mut().insert("Access-Control-Max-Age", config.max_age.to_string().parse().unwrap());
}

