+f retry[T](
    max_attempts: u32,
    base_delay_ms: u64,
    operation: f() -> R[T, s],
) -> R[T, s] / io, async {
    m attempt: u32 = 0;
    loop {
        v result = operation();
        ? result {
            R.Ok(val) => { ret R.Ok(val); },
            R.Err(err) => {
                attempt = attempt + 1;
                ? attempt >= max_attempts { ret R.Err(err); }
                v delay = base_delay_ms * (1 << attempt);
                async.sleep(delay);
            },
        }
    }
}

rust_equivalent.rs_source:
use std::thread;
use std::time::Duration;

pub fn retry<T>(
    max_attempts: u32,
    base_delay_ms: u64,
    operation: impl Fn() -> Result<T, String>,
) -> Result<T, String> {
    let mut attempt = 0;
    loop {
        match operation() {
            Ok(val) => return Ok(val),
            Err(err) => {
                attempt += 1;
                if attempt >= max_attempts { return Err(err); }
                let delay = base_delay_ms * (1 << attempt);
                thread::sleep(Duration::from_millis(delay));
            }
        }
    }
}
